(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["learn0"],{"21df":function(r,n){r.exports="### Docker学习\r\nDocker安装地址(建议在虚拟机上安装)\r\n```\r\nhttps://docs.docker.com/\r\n```\r\n\r\n所以就先得安装一台虚拟机，推荐VirtualBox，安装地址是：\r\n```\r\nhttps://www.virtualbox.org/wiki/Downloads\r\n```\r\n有了虚拟机之后，就可以虚拟化一台Linux机器了。但是如果手动创建的话会比较繁琐，推荐vagrant工具来进行管理就比较方便，vagrant的安装地址是： \r\n```\r\nhttps://www.vagrantup.com\r\n```\r\n\r\n### Vagrant&VirtualBox for Mac\r\n通过vagrant创建一台虚拟机\r\n```s\r\n# 查看vagrant命令\r\nvagrant --help\r\n# 进入到/Users/zhangyu/xnj目录\r\ncd /Users/zhangyu/xnj\r\n# 创建一个centos7文件夹\r\nmkdir centos7\r\n# 进入到centos7下边\r\ncd centos7\r\n# 初始化一个centos7\r\nvagrant init centos/7\r\n# 查看vagrantfile文件\r\nmore vagrantfile\r\n# 创建启动虚拟机\r\nvagrant up\r\n# 进入到刚才创建的虚拟机\r\nvagrant ssh\r\n# 查看当前虚拟机的状态\r\nvagrant status\r\n# 停掉虚拟机\r\nvagrant halt\r\n# 删掉虚拟机\r\nvagrant destroy\r\n# 切换帐号 （root／vagrant，默认密码都是vagrant）\r\nsu\r\n```\r\nvagrantfile文件的配置说明，请参考下边网址：\r\n```\r\nhttps://app.vagrantup.com/boxes/search\r\n```\r\n\r\n### Vagrant&VirtualBox for Windows\r\n```\r\n与Mac类似\r\n```\r\n\r\n### CentOS上安装Docker\r\n\r\n卸载docker\r\n```\r\nsudo yum remove docker \\\r\n                  docker-client \\\r\n                  docker-client-latest \\\r\n                  docker-common \\\r\n                  docker-latest \\\r\n                  docker-latest-logrotate \\\r\n                  docker-logrotate \\\r\n                  docker-selinux \\\r\n                  docker-engine-selinux \\\r\n                  docker-engine\r\n```\r\n\r\n安装packages\r\n```\r\nsudo yum install -y yum-utils \\\r\n  device-mapper-persistent-data \\\r\n  lvm2\r\n```\r\n安装repo\r\n```\r\nsudo yum-config-manager \\\r\n    --add-repo \\\r\n    https://download.docker.com/linux/centos/docker-ce.repo\r\n```\r\n安装docker-ce\r\n```\r\nsudo yum install docker-ce\r\n```\r\n\r\n启动Docker\r\n```\r\nsudo systemctl start docker\r\n```\r\n打印Client和Server端的版本\r\n```\r\nsudo docker version\r\n```\r\n运行一个hello world\r\n```\r\nsudo docker run hello-world\r\n```"},6626:function(r,n,e){"use strict";e.r(n);var o=function(){var r=this,n=r.$createElement,o=r._self._c||n;return o("markdown",{attrs:{source:e("21df")}})},t=[],a=e("2877"),s={},c=Object(a["a"])(s,o,t,!1,null,null,null);c.options.__file="docker.vue";n["default"]=c.exports}}]);